export function nextGeneration(liveCells: Cell[]): Cell[] {
  const survivors = liveCells.filter((cell) => survives(cell, liveCells));
  const candidates: Cell[] = [];
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        candidates.push([x + dx, y + dy]);
      }
    }
  }
  const isLive = (cell: Cell): boolean =>
    liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);
  const seen = new Set<string>();
  const births: Cell[] = [];
  for (const cell of candidates) {
    const key = `${cell[0]},${cell[1]}`;
    if (seen.has(key)) continue;
    seen.add(key);
    if (isLive(cell)) continue;
    if (countLiveNeighbors(cell, liveCells) === 3) births.push(cell);
  }
  return [...survivors, ...births];
}

